        "path": "CrusaderKings3Trainer/CK3Trainer.cs",
        "content": "using System;\nusing System.Collections.Generic;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\n\nnamespace CrusaderKings3Trainer\n{\n    /// <summary>\n    /// Main trainer class for Crusader Kings III, providing memory manipulation utilities.\n    /// </summary>\n    public class CK3Trainer : IDisposable\n    {\n        private Process _gameProcess;\n        private IntPtr _processHandle;\n        private bool _disposed;\n\n        // Import required Windows API functions for memory operations\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool CloseHandle(IntPtr hObject);\n\n        private const uint PROCESS_ALL_ACCESS = 0x1F0FFF;\n\n        /// <summary>\n        /// Attempts to attach to a running Crusader Kings III process.\n        /// </summary>\n        /// <returns>True if successfully attached to the game process.</returns>\n        public bool AttachToGame()\n        {\n            Process[] processes = Process.GetProcessesByName(\"ck3\");\n            if (processes.Length == 0)\n            {\n                Console.WriteLine(\"Crusader Kings III process not found. Ensure the game is running.\");\n                return false;\n            }\n\n            _gameProcess = processes[0];\n            _processHandle = OpenProcess(PROCESS_ALL_ACCESS, false, _gameProcess.Id);\n\n            if (_processHandle == IntPtr.Zero)\n            {\n                Console.WriteLine(\"Failed to open process. Try running as administrator.\");\n                return false;\n            }\n\n            Console.WriteLine($\"Attached to CK3 process (PID: {_gameProcess.Id})\");\n            return true;\n        }\n\n        /// <summary>\n        /// Reads a float value from the game's memory at a specified address.\n        /// </summary>\n        /// <param name=\"address\">Memory address to read from.</param>\n        /// <returns>The float value read from memory, or 0.0f on failure.</returns>\n        public float ReadFloat(IntPtr address)\n        {\n            byte[] buffer = new byte[4];\n            if (ReadProcessMemory(_processHandle, address, buffer, 4, out int bytesRead) && bytesRead == 4)\n            {\n                return BitConverter.ToSingle(buffer, 0);\n            }\n            return 0.0f;\n        }\n\n        /// <summary>\n        /// Writes a float value to the game's memory at a specified address.\n        /// </summary>\n        /// <param name=\"address\">Memory address to write to.</param>\n        /// <param name=\"value\">The float value to write.</param>\n        /// <returns>True if the write was successful.</returns>\n        public bool WriteFloat(IntPtr address, float value)\n        {\n            byte[] buffer = BitConverter.GetBytes(value);\n            return WriteProcessMemory(_processHandle, address, buffer, 4, out int bytesWritten) && bytesWritten == 4;\n        }\n\n        /// <summary>\n        /// Reads an integer value from the game's memory at a specified address.\n        /// </summary>\n        /// <param name=\"address\">Memory address to read from.</param>\n        /// <returns>The integer value read from memory, or 0 on failure.</returns>\n        public int ReadInt(IntPtr address)\n        {\n            byte[] buffer = new byte[4];\n            if (ReadProcessMemory(_processHandle, address, buffer, 4, out int bytesRead) && bytesRead == 4)\n            {\n                return BitConverter.ToInt32(buffer, 0);\n            }\n            return 0;\n        }\n\n        /// <summary>\n        /// Writes an integer value to the game's memory at a specified address.\n        /// </summary>\n        /// <param name=\"address\">Memory address to write to.</param>\n        /// <param name=\"value\">The integer value to write.</param>\n        /// <returns>True if the write was successful.</returns>\n        public bool WriteInt(IntPtr address, int value)\n        {\n            byte[] buffer = BitConverter.GetBytes(value);\n            return WriteProcessMemory(_processHandle, address, buffer, 4, out int bytesWritten) && bytesWritten == 4;\n        }\n\n        /// <summary>\n        /// Finds a memory address by scanning for a pattern (simple placeholder implementation).\n        /// In a real trainer, this would use a pattern scanner or AOB scan.\n        /// </summary>\n        /// <param name=\"moduleName\">The module name (e.g., \"ck3.exe\").</param>\n        /// <param name=\"pattern\">Byte pattern to search for.</param>\n        /// <param name=\"offset\">Offset from the pattern match.</param>\n        /// <returns>The found address, or IntPtr.Zero if not found.</returns>\n        public IntPtr FindPattern(string moduleName, byte[] pattern, int offset)\n        {\n            // Placeholder: In a real project, implement a proper pattern scanner.\n            // This would read the module memory and search for the pattern.\n            Console.WriteLine($\"Pattern scan for module '{moduleName}' not fully implemented.\");\n            return IntPtr.Zero;\n        }\n\n        public void Dispose()\n        {\n            if (!_disposed)\n            {\n                if (_processHandle != IntPtr.Zero)\n                {\n                    CloseHandle(_processHandle);\n                    _processHandle = IntPtr.Zero;\n                }\n                _disposed = true;\n            }\n        }\n    }\n}\n"
