        "path": "CrusaderKings3Trainer/Program.cs",
        "content": "using System;\n\nnamespace CrusaderKings3Trainer\n{\n    /// <summary>\n    /// Entry point for the Crusader Kings III Trainer console application.\n    /// </summary>\n    class Program\n    {\n        static void Main(string[] args)\n        {\n            Console.WriteLine(\"Crusader Kings III Trainer v1.0\");\n            Console.WriteLine(\"===============================\");\n\n            using (var trainer = new CK3Trainer())\n            {\n                if (!trainer.AttachToGame())\n                {\n                    Console.WriteLine(\"Failed to attach to the game. Exiting.\");\n                    return;\n                }\n\n                var features = new TrainerFeatures(trainer);\n                bool running = true;\n\n                while (running)\n                {\n                    Console.WriteLine(\"\\nSelect an option:\");\n                    Console.WriteLine(\"1. Set Gold\");\n                    Console.WriteLine(\"2. Set Prestige\");\n                    Console.WriteLine(\"3. Set Piety\");\n                    Console.WriteLine(\"4. List Features\");\n                    Console.WriteLine(\"5. Exit\");\n                    Console.Write(\"> \");\n\n                    string input = Console.ReadLine();\n                    switch (input)\n                    {\n                        case \"1\":\n                            Console.Write(\"Enter gold amount: \");\n                            if (float.TryParse(Console.ReadLine(), out float gold))\n                            {\n                                features.SetGold(gold);\n                            }\n                            else\n                            {\n                                Console.WriteLine(\"Invalid input.\");\n                            }\n                            break;\n                        case \"2\":\n                            Console.Write(\"Enter prestige amount: \");\n                            if (float.TryParse(Console.ReadLine(), out float prestige))\n                            {\n                                features.SetPrestige(prestige);\n                            }\n                            else\n                            {\n                                Console.WriteLine(\"Invalid input.\");\n                            }\n                            break;\n                        case \"3\":\n                            Console.Write(\"Enter piety amount: \");\n                            if (float.TryParse(Console.ReadLine(), out float piety))\n                            {\n                                features.SetPiety(piety);\n                            }\n                            else\n                            {\n                                Console.WriteLine(\"Invalid input.\");\n                            }\n                            break;\n                        case \"4\":\n                            features.ListFeatures();\n                            break;\n                        case \"5\":\n                            running = false;\n                            break;\n                        default:\n                            Console.WriteLine(\"Unknown option.\");\n                            break;\n                    }\n                }\n            }\n\n            Console.WriteLine(\"Trainer exiting. Goodbye!\");\n        }\n    }\n}\n"
    },
