        "path": "CrusaderKings3Trainer/tests/TrainerFeaturesTests.cs",
        "content": "using System;\nusing Xunit;\nusing Moq;\n\nnamespace CrusaderKings3Trainer.Tests\n{\n    /// <summary>\n    /// Unit tests for TrainerFeatures using mocked CK3Trainer.\n    /// </summary>\n    public class TrainerFeaturesTests\n    {\n        [Fact]\n        public void SetGold_ValidAmount_CallsWriteFloat()\n        {\n            // Arrange\n            var mockTrainer = new Mock<CK3Trainer>();\n            mockTrainer.Setup(t => t.WriteFloat(It.IsAny<IntPtr>(), 1000.0f)).Returns(true);\n            var features = new TrainerFeatures(mockTrainer.Object);\n\n            // Act\n            bool result = features.SetGold(1000.0f);\n\n            // Assert\n            Assert.True(result);\n            mockTrainer.Verify(t => t.WriteFloat(It.IsAny<IntPtr>(), 1000.0f), Times.Once);\n        }\n\n        [Fact]\n        public void SetPrestige_ValidAmount_CallsWriteFloat()\n        {\n            // Arrange\n            var mockTrainer = new Mock<CK3Trainer>();\n            mockTrainer.Setup(t => t.WriteFloat(It.IsAny<IntPtr>(), 500.0f)).Returns(true);\n            var features = new TrainerFeatures(mockTrainer.Object);\n\n            // Act\n            bool result = features.SetPrestige(500.0f);\n\n            // Assert\n            Assert.True(result);\n            mockTrainer.Verify(t => t.WriteFloat(It.IsAny<IntPtr>(), 500.0f), Times.Once);\n        }\n\n        [Fact]\n        public void GetGold_ValidRead_ReturnsValue()\n        {\n            // Arrange\n            var mockTrainer = new Mock<CK3Trainer>();\n            mockTrainer.Setup(t => t.ReadFloat(It.IsAny<IntPtr>())).Returns(2500.0f);\n            var features = new TrainerFeatures(mockTrainer.Object);\n\n            // Act\n            float gold = features.GetGold();\n\n            // Assert\n            Assert.Equal(2500.0f, gold);\n        }\n\n        [Fact]\n        public void Constructor_NullTrainer_ThrowsArgumentNullException()\n        {\n            // Act & Assert\n            Assert.Throws<ArgumentNullException>(() => new TrainerFeatures(null));
